INSERT INTO `references_i18n` (id, reference_id, locale, title, slug, summary, content, featured_image_alt, meta_title, meta_description) VALUES
('14509400-0000-4000-8200-000000000001','14509400-0000-4000-8100-000000000001','tr','Vista Prestige','vista-prestige','Vista Prestige grup şirketi kaydı, kaynak sitede galeri odaklı olarak sunulmaktadır.','<p>Vista Prestige kaynağı, mevcut sitede başlık ve galeri görselleri ile sunulmaktadır. Bu kayıt, görsel referans setini ekosistem veritabanına taşımak için oluşturulmuştur.</p>','Vista Prestige','Vista Prestige | vistaseeds','Vista Prestige grup şirketi görselleri ve referans kaydı.'),
('14509400-0000-4000-8201-000000000001','14509400-0000-4000-8100-000000000001','en','Vista Prestige','vista-prestige','The Vista Prestige group-company entry is presented as a gallery on the source site.','<p>The Vista Prestige source page is presented with a title and gallery visuals. This record carries that visual reference set into the ecosystem database.</p>','Vista Prestige','Vista Prestige | vistaseeds','Reference record and visuals for the Vista Prestige group company.'),
('14509400-0000-4000-8202-000000000001','14509400-0000-4000-8100-000000000001','de','Vista Prestige','vista-prestige','Der Eintrag zur Gruppengesellschaft Vista Prestige wird auf der Quellseite galerieorientiert dargestellt.','<p>Die Quelle zu Vista Prestige wird mit einem Titel und Galerie-Bildern dargestellt. Dieser Datensatz uebertraegt dieses visuelle Referenzset in die Okosystem-Datenbank.</p>','Vista Prestige','Vista Prestige | vistaseeds','Referenzeintrag und Bildmaterial zur Gruppengesellschaft Vista Prestige.'),
('14509400-0000-4000-8200-000000000002','14509400-0000-4000-8100-000000000002','tr','GES Sistemleri','ges-sistemleri','GES Sistemleri grup şirketi kaydı, kaynak sitede galeri odaklı olarak sunulmaktadır.','<p>GES Sistemleri kaynağı, mevcut sitede başlık ve galeri görselleri ile yer almaktadır. Bu kayıt, görsel referans setini yerel seed yapısına taşır.</p>','GES Sistemleri','GES Sistemleri | vistaseeds','GES Sistemleri grup şirketi görselleri ve referans kaydı.'),
('14509400-0000-4000-8201-000000000002','14509400-0000-4000-8100-000000000002','en','GES Sistemleri','ges-sistemleri','The GES Sistemleri group-company entry is presented as a gallery on the source site.','<p>The GES Sistemleri source page contains a title and gallery visuals. This record carries that visual reference set into the local seed structure.</p>','GES Sistemleri','GES Sistemleri | vistaseeds','Reference record and visuals for the GES Sistemleri group company.'),
('14509400-0000-4000-8202-000000000002','14509400-0000-4000-8100-000000000002','de','GES Sistemleri','ges-sistemleri','Der Eintrag zur Gruppengesellschaft GES Sistemleri wird auf der Quellseite galerieorientiert dargestellt.','<p>Die Quelle zu GES Sistemleri enthaelt einen Titel und Galerie-Bilder. Dieser Datensatz uebertraegt dieses visuelle Referenzset in die lokale Seed-Struktur.</p>','GES Sistemleri','GES Sistemleri | vistaseeds','Referenzeintrag und Bildmaterial zur Gruppengesellschaft GES Sistemleri.'),
('14509400-0000-4000-8200-000000000003','14509400-0000-4000-8100-000000000003','tr','Karaşah İş merkezi','karasah-is-merkezi','Karaşah İş merkezi projemizin görselleri.','<p>Karaşah İş merkezi projemizin görselleri.</p>','Karaşah İş merkezi','Karaşah İş merkezi | vistaseeds','Karaşah İş merkezi projesine ait görseller ve referans kaydı.'),
('14509400-0000-4000-8201-000000000003','14509400-0000-4000-8100-000000000003','en','Karaşah İş merkezi','karasah-is-merkezi','Visuals from our Karaşah İş Merkezi project.','<p>Visuals from our Karaşah İş Merkezi project.</p>','Karaşah İş merkezi','Karaşah İş merkezi | vistaseeds','Reference record and visuals for the Karaşah İş Merkezi project.'),
('14509400-0000-4000-8202-000000000003','14509400-0000-4000-8100-000000000003','de','Karaşah İş merkezi','karasah-is-merkezi','Bilder aus unserem Projekt Karaşah İş Merkezi.','<p>Bilder aus unserem Projekt Karaşah İş Merkezi.</p>','Karaşah İş merkezi','Karaşah İş merkezi | vistaseeds','Referenzeintrag und Bildmaterial zum Projekt Karaşah İş Merkezi.'),
('14509400-0000-4000-8200-000000000004','14509400-0000-4000-8100-000000000004','tr','Bereket Fide İnşaat','bereket-fide-insaat','Bereket Fide, sera sebzeciliğinin gelişmesiyle artan hazır fide talebini karşılamak amacıyla; 2006 yılında, Antalya’nın Aksu Çamköy beldesinde üretime başlamıştır.','<p>Bereket Fide, sera sebzeciliğinin gelişmesiyle artan hazır fide talebini karşılamak amacıyla; 2006 yılında, Antalya’nın Aksu Çamköy beldesinde üretime başlamıştır.</p><p>Bugün 32 bin m²’lik alan üzerinde 24 bin m² modern seralarıyla normal ve aşılı fide üretimi yapmaktadır. İşletme, tamamen bilgisayar kontrollü sulama, ilaçlama, ısıtma, sıcaklık ve nem yönetimiyle fide üretimi gerçekleştirmektedir.</p><p>Kaynak sitedeki anlatıma göre, gerektiğinde 3 bin m² aşı odası alanı ile birlikte toplam kapasite 16-17 milyon aşılı fide ve 18-20 milyon normal fide düzeyine ulaşabilmektedir.</p>','Bereket Fide İnşaat','Bereket Fide İnşaat | vistaseeds','Bereket Fide İnşaat ve üretim altyapısına ait kaynak site referans kaydı.'),
('14509400-0000-4000-8201-000000000004','14509400-0000-4000-8100-000000000004','en','Bereket Fide İnşaat','bereket-fide-insaat','Bereket Fide started production in 2006 in Aksu Çamköy, Antalya, to meet the growing demand for ready seedlings in greenhouse vegetable cultivation.','<p>Bereket Fide started production in 2006 in Aksu Çamköy, Antalya, to meet the growing demand for ready seedlings driven by greenhouse vegetable cultivation.</p><p>Today, it produces standard and grafted seedlings in 24,000 m² of modern greenhouses on a total area of 32,000 m². According to the source site, production is carried out in facilities managed with fully computerized irrigation, spraying, heating, temperature, and humidity control.</p><p>The same source states that, when required, the facility can reach 16-17 million grafted seedlings and 18-20 million standard seedlings with a 3,000 m² grafting room.</p>','Bereket Fide İnşaat','Bereket Fide İnşaat | vistaseeds','Source-site reference entry for Bereket Fide İnşaat and its production infrastructure.'),
('14509400-0000-4000-8202-000000000004','14509400-0000-4000-8100-000000000004','de','Bereket Fide İnşaat','bereket-fide-insaat','Bereket Fide nahm 2006 in Aksu Çamköy, Antalya, die Produktion auf, um die steigende Nachfrage nach fertigen Setzlingen im Gemueseanbau unter Glas zu bedienen.','<p>Bereket Fide nahm 2006 in Aksu Çamköy, Antalya, die Produktion auf, um die steigende Nachfrage nach fertigen Setzlingen im Gemueseanbau unter Glas zu bedienen.</p><p>Heute werden auf einer Gesamtflaeche von 32.000 m² in 24.000 m² modernen Gewaechshaeusern normale und veredelte Setzlinge produziert. Laut Quellseite erfolgt die Produktion in Anlagen mit vollstaendig computergesteuerter Bewaesserung, Spruehung, Heizung sowie Temperatur- und Feuchteregelung.</p><p>Dieselbe Quelle gibt an, dass die Anlage bei Bedarf mit einem 3.000 m² grossen Veredelungsraum 16-17 Millionen veredelte und 18-20 Millionen normale Setzlinge erreichen kann.</p>','Bereket Fide İnşaat','Bereket Fide İnşaat | vistaseeds','Referenzeintrag der Quellseite zu Bereket Fide İnşaat und seiner Produktionsinfrastruktur.'),
('14509400-0000-4000-8200-000000000005','14509400-0000-4000-8100-000000000005','tr','Vista Lagoon','vista-lagoon','Vista lagoon projemiz. İnşaat ve planlama.','<p>Vista Lagoon projemiz. İnşaat ve planlama.</p>','Vista Lagoon','Vista Lagoon | vistaseeds','Vista Lagoon projesine ait görseller ve referans kaydı.'),
('14509400-0000-4000-8201-000000000005','14509400-0000-4000-8100-000000000005','en','Vista Lagoon','vista-lagoon','Our Vista Lagoon project. Construction and planning.','<p>Our Vista Lagoon project. Construction and planning.</p>','Vista Lagoon','Vista Lagoon | vistaseeds','Reference record and visuals for the Vista Lagoon project.'),
('14509400-0000-4000-8202-000000000005','14509400-0000-4000-8100-000000000005','de','Vista Lagoon','vista-lagoon','Unser Projekt Vista Lagoon. Bau und Planung.','<p>Unser Projekt Vista Lagoon. Bau und Planung.</p>','Vista Lagoon','Vista Lagoon | vistaseeds','Referenzeintrag und Bildmaterial zum Projekt Vista Lagoon.'),
('14509400-0000-4000-8200-000000000006','14509400-0000-4000-8100-000000000006','tr','Vista Sunset','vista-sunset','Vista Sunset grup şirketi kaydı, kaynak sitede galeri odaklı olarak sunulmaktadır.','<p>Vista Sunset kaynağı, mevcut sitede başlık ve galeri görselleri ile sunulmaktadır. Bu kayıt, görsel referans setini ekosistem veritabanına taşımak için oluşturulmuştur.</p>','Vista Sunset','Vista Sunset | vistaseeds','Vista Sunset grup şirketi görselleri ve referans kaydı.'),
('14509400-0000-4000-8201-000000000006','14509400-0000-4000-8100-000000000006','en','Vista Sunset','vista-sunset','The Vista Sunset group-company entry is presented as a gallery on the source site.','<p>The Vista Sunset source page is presented with a title and gallery visuals. This record carries that visual reference set into the ecosystem database.</p>','Vista Sunset','Vista Sunset | vistaseeds','Reference record and visuals for the Vista Sunset group company.'),
('14509400-0000-4000-8202-000000000006','14509400-0000-4000-8100-000000000006','de','Vista Sunset','vista-sunset','Der Eintrag zur Gruppengesellschaft Vista Sunset wird auf der Quellseite galerieorientiert dargestellt.','<p>Die Quelle zu Vista Sunset wird mit einem Titel und Galerie-Bildern dargestellt. Dieser Datensatz uebertraegt dieses visuelle Referenzset in die Okosystem-Datenbank.</p>','Vista Sunset','Vista Sunset | vistaseeds','Referenzeintrag und Bildmaterial zur Gruppengesellschaft Vista Sunset.'),
('14509400-0000-4000-8200-000000000007','14509400-0000-4000-8100-000000000007','tr','Vista Lara Villaları','vista-lara-villalari','Vista Lara Villaları grup şirketi kaydı, kaynak sitede galeri odaklı olarak sunulmaktadır.','<p>Vista Lara Villaları kaynağı, mevcut sitede başlık ve galeri görselleri ile sunulmaktadır. Bu kayıt, görsel referans setini ekosistem veritabanına taşımak için oluşturulmuştur.</p>','Vista Lara Villaları','Vista Lara Villaları | vistaseeds','Vista Lara Villaları grup şirketi görselleri ve referans kaydı.'),
('14509400-0000-4000-8201-000000000007','14509400-0000-4000-8100-000000000007','en','Vista Lara Villaları','vista-lara-villalari','The Vista Lara Villaları group-company entry is presented as a gallery on the source site.','<p>The Vista Lara Villaları source page is presented with a title and gallery visuals. This record carries that visual reference set into the ecosystem database.</p>','Vista Lara Villaları','Vista Lara Villaları | vistaseeds','Reference record and visuals for the Vista Lara Villaları group company.'),
('14509400-0000-4000-8202-000000000007','14509400-0000-4000-8100-000000000007','de','Vista Lara Villaları','vista-lara-villalari','Der Eintrag zur Gruppengesellschaft Vista Lara Villaları wird auf der Quellseite galerieorientiert dargestellt.','<p>Die Quelle zu Vista Lara Villaları wird mit einem Titel und Galerie-Bildern dargestellt. Dieser Datensatz uebertraegt dieses visuelle Referenzset in die Okosystem-Datenbank.</p>','Vista Lara Villaları','Vista Lara Villaları | vistaseeds','Referenzeintrag und Bildmaterial zur Gruppengesellschaft Vista Lara Villaları.');
