-- vistaseeds group companies -> references refresh
-- Source: https://www.vistaseeds.com.tr/grup-sirketlerimiz and detail pages
-- Note: where the source page only exposes title + gallery, summary/content are normalized as gallery records.
SET NAMES utf8mb4;
SET time_zone = '+00:00';

DELETE FROM reference_images_i18n WHERE image_id LIKE '14509400-%' OR image_id LIKE 'refimg-%';
DELETE FROM reference_images WHERE id LIKE '14509400-%' OR id LIKE 'refimg-%';
DELETE FROM `references_i18n` WHERE reference_id LIKE '14509400-%' OR reference_id LIKE 'ref-%';
DELETE FROM `references` WHERE id LIKE '14509400-%' OR id LIKE 'ref-%';
DELETE FROM storage_assets WHERE id LIKE '14509400-%' OR id LIKE '00009400-ref%';





